-- init.sql — Base EduAI complète (Docker)
-- Données réelles : 12 classes, 8 matières, 235 étudiants, ~1880 notes
-- ════════════════════════════════════════════════════════════════

-- ─── TABLES ────────────────────────────────────────────────────

CREATE TABLE classes (
    id SERIAL PRIMARY KEY,
    nom_classe VARCHAR(50) UNIQUE NOT NULL
);

CREATE TABLE matieres (
    id SERIAL PRIMARY KEY,
    nom_matiere VARCHAR(100) UNIQUE NOT NULL
);

CREATE TABLE etudiants (
    id SERIAL PRIMARY KEY,
    code_etudiant VARCHAR(20) UNIQUE,
    nom VARCHAR(100),
    prenom VARCHAR(100),
    date_naissance DATE,
    classe_id INT REFERENCES classes(id)
);

CREATE TABLE notes (
    id SERIAL PRIMARY KEY,
    etudiant_id INT NOT NULL REFERENCES etudiants(id),
    matiere_id INT NOT NULL REFERENCES matieres(id),
    note FLOAT CHECK (note >= 0 AND note <= 20)
);

